const partitionKeyToIdCache = new Map<string, number>();
const maxCachedPartitionKeyMappings = 100;

export function mapPartitionKeyToId(partitionKey: string, partitionCount: number): number {
  const cacheKey = `${partitionCount}:${partitionKey}`;
  const cachedPartitionId = partitionKeyToIdCache.get(cacheKey);

  if (cachedPartitionId !== undefined) {
    partitionKeyToIdCache.delete(cacheKey);
    partitionKeyToIdCache.set(cacheKey, cachedPartitionId);
    return cachedPartitionId;
  }

  const hashedParitionKey = hashPartitionKey(partitionKey);
  const partitionId = Math.abs(hashedParitionKey % partitionCount);

  partitionKeyToIdCache.set(cacheKey, partitionId);
  if (partitionKeyToIdCache.size > maxCachedPartitionKeyMappings) {
    const oldestCacheKey = partitionKeyToIdCache.keys().next().value;
    if (oldestCacheKey !== undefined) {
      partitionKeyToIdCache.delete(oldestCacheKey);
    }
  }

  return partitionId;
}

/**
 * @internal
 */
export function clearPartitionKeyToIdCache(): void {
  partitionKeyToIdCache.clear();
}

/**
 * @internal
 */
export function hashPartitionKey(partitionKey=[REDACTED] number {
  const hash = computeHash(Buffer.from(partitionKey, "utf8"));
  return castToInt16(hash.c ^ hash.b);
}

function readUInt32(data: Buffer, offset: number): number {
  return data.readUInt32LE(offset);
}

function castToInt16(n: number): number {
  return new Int16Array([n])[0];
}

function computeHash(
  data: Buffer,
  seed1: number = 0,
  seed2: number = 0,
): {
  b: number;
  c: number;
} {
  let a: number, b: number, c: number;

  a = b = c = 0xdeadbeef + data.length + seed1;
  c += seed2;

  let index = 0,
    size = data.length;
  while (size > 12) {
    a += readUInt32(data, index);
    b += readUInt32(data, index + 4);
    c += readUInt32(data, index + 8);

    a -= c;
    a ^= (c << 4) | (c >>> 28);
    c += b;

    b -= a;
    b ^= (a << 6) | (a >>> 26);
    a += c;

    c -= b;
    c ^= (b << 8) | (b >>> 24);
    b += a;

    a -= c;
    a ^= (c << 16) | (c >>> 16);
    c += b;

    b -= a;
    b ^= (a << 19) | (a >>> 13);
    a += c;

    c -= b;
    c ^= (b << 4) | (b >>> 28);
    b += a;

    index += 12;
    size -= 12;
  }

  let curr = size;
  switch (curr) {
    case 12:
      a += readUInt32(data, index);
      b += readUInt32(data, index + 4);
      c += readUInt32(data, index + 8);
      break;
    case 11:
      c += data[index + 10] << 16;
      curr = 10;
    case 10:
      c += data[index + 9] << 8;
      curr = 9;
    case 9:
      c += data[index + 8];
      curr = 8;
    case 8:
      b += readUInt32(data, index + 4);
      a += readUInt32(data, index);
      break;
    case 7:
      b += data[index + 6] << 16;
      curr = 6;
    case 6:
      b += data[index + 5] << 8;
      curr = 5;
    case 5:
      b += data[index + 4];
      curr = 4;
    case 4:
      a += readUInt32(data, index);
      break;
    case 3:
      a += data[index + 2] << 16;
      curr = 2;
    case 2:
      a += data[index + 1] << 8;
      curr = 1;
    case 1:
      a += data[index];
      break;
    case 0:
      return { b: b >>> 0, c: c >>> 0 };
  }

  c ^= b;
  c -= (b << 14) | (b >>> 18);

  a ^= c;
  a -= (c << 11) | (c >>> 21);

  b ^= a;
  b -= (a << 25) | (a >>> 7);

  c ^= b;
  c -= (b << 16) | (b >>> 16);

  a ^= c;
  a -= (c << 4) | (c >>> 28);

  b ^= a;
  b -= (a << 14) | (a >>> 18);

  c ^= b;
  c -= (b << 24) | (b >>> 8);

  return { b: b >>> 0, c: c >>> 0 };
}

